import { useMap } from '@vis.gl/react-maplibre';
import { useRef, type KeyboardEvent as ReactKeyboardEvent } from 'react';
import { useIntl } from 'react-intl';

import { _ChartToolbarRenderer as ChartToolbarRenderer } from '@dynatrace/strato-components/charts';
import { ZoomInIcon, ZoomOutIcon } from '@dynatrace/strato-icons';

import { useMapZoomState } from '../../../store/selectors.js';
import { TOOLBAR_MESSAGES } from '../constants.js';
import { useA11yToolbarTabIndex } from '../hooks/use-a11y-toolbar-tab-index.js';

type ZoomBehavior = 'zoom-in' | 'zoom-out';
export const MapZoomInOutButtons = () => {
  const { current: map } = useMap();
  const { zoomInEnabled, zoomOutEnabled } = useMapZoomState();

  const zoomInButtonRef = useRef<HTMLButtonElement | null>(null);
  const zoomButtonOutRef = useRef<HTMLButtonElement | null>(null);
  const intl = useIntl();
  const tabIndexIn = useA11yToolbarTabIndex('zoom-in');
  const tabIndexOut = useA11yToolbarTabIndex('zoom-out');

  const handleZoomKeyboardMode = (
    event: ReactKeyboardEvent,
    zoomBehavior: ZoomBehavior,
  ) => {
    if (event.code === 'Enter') {
      handleZoomStepToolbarMode(zoomBehavior);
    }
  };

  const handleZoomStepToolbarMode = (zoomBehavior: ZoomBehavior) => {
    if (zoomBehavior === 'zoom-in') {
      map?.zoomIn();
    }
    if (zoomBehavior === 'zoom-out') {
      map?.zoomOut();
    }
  };

  return (
    <>
      <ChartToolbarRenderer.Control
        ref={zoomInButtonRef}
        prefixIcon={<ZoomInIcon />}
        tooltipText={intl.formatMessage(TOOLBAR_MESSAGES.zoomActionZoomIn)}
        testId="map-toolbar-zoom-in"
        onKeyDown={(event) => handleZoomKeyboardMode(event, 'zoom-in')}
        onClick={() => handleZoomStepToolbarMode('zoom-in')}
        tabIndex={tabIndexIn}
        disabled={!zoomInEnabled}
      />
      <ChartToolbarRenderer.Control
        ref={zoomButtonOutRef}
        prefixIcon={<ZoomOutIcon />}
        tooltipText={intl.formatMessage(TOOLBAR_MESSAGES.zoomActionZoomOut)}
        testId="map-toolbar-zoom-out"
        onKeyDown={(event) => handleZoomKeyboardMode(event, 'zoom-out')}
        onClick={() => handleZoomStepToolbarMode('zoom-out')}
        tabIndex={tabIndexOut}
        disabled={!zoomOutEnabled}
      />
    </>
  );
};
